#include <bits/stdc++.h>
using namespace std;
const int mod=1e9+7;
int n,a[51];
long long ans=1;
int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    sort(a+1,a+n+1);
    for(int i=1;i<=n;i++){
        if(a[i]<i){
            printf("0");
            return 0;
        }
        ans*=a[i]-i+1,ans%=mod;
    }
    printf("%lld",ans);
    return 0;
}
